import pytest
from app.middleware.auth import AuthMiddleware, Unauthorized


class FakeRequest:
    def __init__(self, headers=None, cookies=None):
        self.headers = headers or {}
        self.cookies = cookies or {}


@pytest.mark.parametrize("headers", [
    {"X-Gateway-User-Id": "admin"},                              # no signature
    {"X-Gateway-User-Id": "admin", "X-Gateway-Signature": ""},   # empty signature
    {"X-Gateway-User-Id": "admin", "X-Gateway-Signature": "deadbeef"},  # forged signature
    {"X-User-Id": "admin"},                                      # legacy unsigned header
])
def test_gateway_identity_header_requires_valid_hmac(headers):
    """Regression: an unsigned or badly-signed gateway identity header must
    never authenticate the caller. The prior bug returned User(id=gateway_uid)
    unconditionally, letting any client impersonate any user by setting a header."""
    mw = AuthMiddleware(sessions={}, hmac_key=b"test-secret")
    with pytest.raises(Unauthorized):
        mw.resolve_user(FakeRequest(headers=headers))
```

Four forged-header shapes, one assertion: none of them authenticate. Add a positive-path test separately (valid HMAC → `User(id="admin")`) so a buggy `_verify` that rejects everything doesn't pass this suite silently.
